#include <stddef.h>

/* Read exactly n bytes (APUE-style readn) */
ssize_t readn(int fd, void *buf, size_t n) {
    size_t nleft = n;
    ssize_t nread;
    char *ptr = (char *)buf;

    while (nleft > 0) {
        nread = read(fd, ptr, nleft);
        if (nread == -1) {
            if (errno == EINTR)
                continue;   /* interrupted, retry */
            return -1;      /* real error */
        }
        if (nread == 0)
            break;          /* EOF */
        nleft -= (size_t)nread;
        ptr += nread;
    }
    return (ssize_t)(n - nleft);
}

/* Write exactly n bytes (APUE-style writen) */
ssize_t writen(int fd, const void *buf, size_t n) {
    size_t nleft = n;
    ssize_t nwritten;
    const char *ptr = (const char *)buf;

    while (nleft > 0) {
        nwritten = write(fd, ptr, nleft);
        if (nwritten == -1) {
            if (errno == EINTR)
                continue;
            return -1;
        }
        nleft -= (size_t)nwritten;
        ptr += nwritten;
    }
    return (ssize_t)n;
}

#include <unistd.h>
#include <errno.h>

ssize_t readn(int fd, void *buf, size_t n) {
    size_t left = n;
    char *p = (char *)buf;
    while (left > 0) {
        ssize_t nr = read(fd, p, left);
        if (nr == -1) { if (errno == EINTR) continue; return -1; }
        if (nr == 0) break;
        left -= nr; p += nr;
    }
    return (ssize_t)(n - left);
}

