    printf("Access mode: ");
    switch (flags & O_ACCMODE) {
        case O_RDONLY: printf("O_RDONLY\n"); break;
        case O_WRONLY: printf("O_WRONLY\n"); break;
        case O_RDWR:   printf("O_RDWR\n");   break;
