    if (fd == -1) { perror("open"); return 1; }

    /* Write at beginning */
    write(fd, "A", 1);

    /* Seek far ahead -- creates a hole */
    off_t pos = lseek(fd, 1000000, SEEK_SET);
    printf("Seeked to offset: %lld\n", (long long)pos);

    /* Write at the new position */
    write(fd, "B", 1);

    close(fd);

    /* Check file size vs disk usage */
    struct stat st;
    stat("sparse.dat", &st);
    printf("Logical size:  %lld bytes\n", (long long)st.st_size);    /* 1000001 */
    printf("Disk blocks:   %lld (512-byte blocks)\n", (long long)st.st_blocks);
    /* st_blocks will be much less than 1000001/512 */

    return 0;
}

