int main(void) {
    /* Two open() calls on the same file: independent offsets */
    int fd1 = open("data.txt", O_RDWR | O_CREAT | O_TRUNC, 0644);
    int fd2 = open("data.txt", O_RDWR);
    /* fd1 and fd2 have DIFFERENT open file table entries */
    /* They have independent offsets */

    write(fd1, "AAAA", 4);  /* fd1 offset = 4 */
    write(fd2, "BB", 2);    /* fd2 offset = 2 (overwrites first 2 bytes) */
    /* File contents: "BBAA" */

    /* dup creates shared offset */
    int fd3 = dup(fd1);
    /* fd3 shares open file table entry with fd1 */
    off_t off1 = lseek(fd1, 0, SEEK_CUR);  /* offset = 4 */
    off_t off3 = lseek(fd3, 0, SEEK_CUR);  /* offset = 4 (same!) */
    printf("fd1 offset=%lld, fd3 offset=%lld\n",
           (long long)off1, (long long)off3);

    write(fd1, "CC", 2);  /* offset advances to 6 for BOTH fd1 and fd3 */
    off3 = lseek(fd3, 0, SEEK_CUR);
    printf("After write via fd1, fd3 offset=%lld\n", (long long)off3);  /* 6 */

    close(fd1);
    close(fd2);
    close(fd3);
    return 0;
}

