/* Safe concurrent log writing */
void append_log(const char *msg) {
    int fd = open("app.log", O_WRONLY | O_APPEND | O_CREAT, 0644);
    if (fd == -1) { perror("open log"); return; }
    /* write() is atomic to EOF thanks to O_APPEND */
    write(fd, msg, strlen(msg));
    close(fd);
}

/* Safe lock file creation */
int acquire_lock(const char *lockpath) {
    int fd = open(lockpath, O_WRONLY | O_CREAT | O_EXCL, 0600);
    if (fd == -1) {
        if (errno == EEXIST) {
            fprintf(stderr, "Lock already held\n");
            return -1;
        }
        perror("open lockfile");
        return -1;
    }
    /* Write PID to lock file for debugging */
    char buf[32];
    int len = snprintf(buf, sizeof(buf), "%d\n", getpid());
    write(fd, buf, (size_t)len);
    close(fd);
    return 0;
}

void release_lock(const char *lockpath) {
    unlink(lockpath);
}

int main(void) {
    append_log("Server started\n");

    if (acquire_lock("/tmp/myapp.lock") == 0) {
        printf("Lock acquired\n");
        /* do work ... */
        release_lock("/tmp/myapp.lock");
    }
    return 0;
}

