#define PAGE_SIZE 4096

static int shared_fd;

void *reader_thread(void *arg) {
    int page_num = *(int *)arg;
    char buf[PAGE_SIZE];
    /* pread: read at offset without affecting shared file offset */
    ssize_t n = pread(shared_fd, buf, PAGE_SIZE,
                      (off_t)page_num * PAGE_SIZE);
    if (n > 0) {
        printf("Thread read page %d: first byte = 0x%02x\n",
               page_num, (unsigned char)buf[0]);
    }
    return NULL;
}

int main(void) {
    shared_fd = open("database.dat", O_RDWR | O_CREAT, 0644);
    if (shared_fd == -1) { perror("open"); return 1; }

    /* Write some pages using pwrite */
    char page0[PAGE_SIZE], page1[PAGE_SIZE];
    memset(page0, 0xAA, PAGE_SIZE);
    memset(page1, 0xBB, PAGE_SIZE);
    pwrite(shared_fd, page0, PAGE_SIZE, 0);
    pwrite(shared_fd, page1, PAGE_SIZE, PAGE_SIZE);

    /* Read different pages concurrently -- no locking needed */
    pthread_t t1, t2;
    int p0 = 0, p1 = 1;
    pthread_create(&t1, NULL, reader_thread, &p0);
    pthread_create(&t2, NULL, reader_thread, &p1);
    pthread_join(t1, NULL);
    pthread_join(t2, NULL);

    close(shared_fd);
    return 0;
}

