int main(void) {
    int fd = open("output.dat", O_WRONLY | O_CREAT | O_TRUNC, 0644);
    if (fd == -1) { perror("open"); return 1; }

    /* Write header + body in one atomic operation */
    char header[] = "HTTP/1.1 200 OK\r\nContent-Length: 13\r\n\r\n";
    char body[] = "Hello, World!";

    struct iovec iov[2];
    iov[0].iov_base = header;
    iov[0].iov_len  = strlen(header);
    iov[1].iov_base = body;
    iov[1].iov_len  = strlen(body);

    ssize_t nwritten = writev(fd, iov, 2);
    printf("writev wrote %zd bytes\n", nwritten);
    close(fd);

    /* Read back into separate buffers */
    fd = open("output.dat", O_RDONLY);
    char hdr_buf[64];
    char body_buf[32];
    struct iovec riov[2];
    riov[0].iov_base = hdr_buf;
    riov[0].iov_len  = strlen(header);  /* read exactly header size */
    riov[1].iov_base = body_buf;
    riov[1].iov_len  = strlen(body);

    ssize_t nread = readv(fd, riov, 2);
    body_buf[strlen(body)] = '\0';
    printf("readv read %zd bytes, body: %s\n", nread, body_buf);

    close(fd);
    return 0;
}

