#include <stdio.h>
#include <unistd.h>
#include <fcntl.h>

int main(void) {
    /* FILE* is buffered -- fewer syscalls */
    FILE *fp = fopen("test.txt", "w");
    if (!fp) { perror("fopen"); return 1; }
    fprintf(fp, "Line %d\n", 1);   /* stays in buffer */
    fprintf(fp, "Line %d\n", 2);   /* stays in buffer */
    fflush(fp);                     /* NOW written to disk */

    /* Get underlying fd from FILE* */
    int fd = fileno(fp);
    printf("Underlying fd = %d\n", fd);

    /* Can mix, but dangerous without fflush first */
    fflush(fp);
    write(fd, "raw write\n", 10);  /* bypasses buffer */

    fclose(fp);  /* flushes buffer and closes fd */

    /* Wrap an fd in a FILE* */
    int pipefd[2];
    pipe(pipefd);
    FILE *pipe_fp = fdopen(pipefd[0], "r");
    if (pipe_fp) {
        /* Can now use fgets, fscanf, etc. on the pipe */
        fclose(pipe_fp);  /* also closes pipefd[0] */
    }
    close(pipefd[1]);

    return 0;
}

