#include <fcntl.h>
#include <unistd.h>
#include <stdio.h>
#include <errno.h>

int lock_region(int fd, int type, off_t start, off_t len) {
    struct flock fl;
    fl.l_type   = (short)type;
    fl.l_whence = SEEK_SET;
    fl.l_start  = start;
    fl.l_len    = len;     /* 0 = lock to EOF */

    if (fcntl(fd, F_SETLK, &fl) == -1) {
        if (errno == EAGAIN || errno == EACCES) {
            fprintf(stderr, "Region locked by another process\n");
            return -1;
        }
        perror("fcntl F_SETLK");
        return -1;
    }
    return 0;
}

int lock_region_wait(int fd, int type, off_t start, off_t len) {
    struct flock fl;
    fl.l_type   = (short)type;
    fl.l_whence = SEEK_SET;
    fl.l_start  = start;
    fl.l_len    = len;
    return fcntl(fd, F_SETLKW, &fl);  /* blocks until lock acquired */
}

int unlock_region(int fd, off_t start, off_t len) {
    struct flock fl;
    fl.l_type   = F_UNLCK;
    fl.l_whence = SEEK_SET;
    fl.l_start  = start;
    fl.l_len    = len;
    return fcntl(fd, F_SETLK, &fl);
}

