    if (lock_region(fd, F_WRLCK, 0, 100) == 0) {
        printf("Locked bytes 0-99 for writing\n");
        write(fd, "exclusive data", 14);
        unlock_region(fd, 0, 100);
    }

    /* Lock entire file (l_len=0 means to EOF) */
    if (lock_region(fd, F_RDLCK, 0, 0) == 0) {
        printf("Read-locked entire file\n");
        unlock_region(fd, 0, 0);
    }

    close(fd);
    return 0;
}

